parsed_data = []
for record in data:
    cpc_str = record.get('cpc', '[]')
    pub_date_str = record.get('publication_date', '')

    # Extract year from publication date (format: "Aug 3rd, 2021")
    year_match = re.search(r',\s*(\d{4})', pub_date_str)
    if year_match:
        year = int(year_match.group(1))
    else:
        continue

